import{_ as e,c as n,o as t,a4 as o}from"./chunks/framework.ttppV29E.js";const i="/assets/client-connection-create.CUwYCtx-.png",a="/assets/client-connection-use.BLq-2tw_.png",f=JSON.parse('{"title":"Connections","description":"","frontmatter":{},"headers":[],"relativePath":"docs/connections/client-connections.md","filePath":"docs/connections/client-connections.md","lastUpdated":1775819991000}'),s={name:"docs/connections/client-connections.md"},r=o('<h1 id="connections" tabindex="-1">Connections <a class="header-anchor" href="#connections" aria-label="Permalink to &quot;Connections&quot;">​</a></h1><p>Connections allow you to configure and manage integrations with external services. Here you can create and manage <strong>Client Connections</strong> for secure authentication in HTTP requests.</p><h2 id="client-connections" tabindex="-1">Client Connections <a class="header-anchor" href="#client-connections" aria-label="Permalink to &quot;Client Connections&quot;">​</a></h2><p>A Client Connection stores the details required to obtain an access token from an OAuth2 or OpenID Connect authorization server. This is helpful when you may have multiple endpoints or tasks that need to authenticate with the same external service and allows you to centralize and manage these credentials in one place.</p><h3 id="creating-a-client-connection" tabindex="-1">Creating a Client Connection <a class="header-anchor" href="#creating-a-client-connection" aria-label="Permalink to &quot;Creating a Client Connection&quot;">​</a></h3><p>To add a new Client Connection:</p><ol><li>Go to the <strong>Connections</strong> section in AireGlu.</li><li>Click the <strong>Add</strong> button.</li><li>Fill in the required fields: <ul><li><strong>Key</strong>: A unique identifier for this connection (e.g., <code>my-client</code>).</li><li><strong>Display Name</strong>: A friendly name for easy reference.</li><li><strong>Client ID</strong>: The client identifier registered with your authorization server.</li><li><strong>Access Token URL</strong>: The token endpoint URL provided by your authorization server.</li></ul></li><li>Under <strong>Secret Configuration</strong>, choose how to provide the client secret: <ul><li><strong>Client Secret</strong>: Reference an AireGlu secret that contains the client secret value.</li><li><strong>Private Key JWT</strong>: Reference an AireGlu secret that contains a private key for JWT-based client authentication, and specify the key ID, formats, and signing algorithm as needed.</li></ul></li><li>(Optional) Add any additional parameters required by your authorization server (e.g., <code>scope</code>).</li><li>Click <strong>Save connection</strong>.</li></ol><p><img src="'+i+'" alt="Create Client Connection"></p><h3 id="using-a-client-connection-in-http-request-tasks" tabindex="-1">Using a Client Connection in HTTP Request Tasks <a class="header-anchor" href="#using-a-client-connection-in-http-request-tasks" aria-label="Permalink to &quot;Using a Client Connection in HTTP Request Tasks&quot;">​</a></h3><p>Once you have created a Client Connection, you can use it to authenticate HTTP requests in your endpoint tasks:</p><ol><li>In your endpoint, add or edit an <strong>HTTP Request Task</strong>.</li><li>Go to the <strong>Authorisation</strong> tab.</li><li>Set <strong>Auth Type</strong> to <strong>Client Connection</strong>.</li><li>Search and select the desired <strong>Client Connection</strong>.</li><li>(Optional) Override any parameters (such as <code>scope</code>) for this specific request.</li></ol><p>When the task runs, AireGlu will automatically:</p><ul><li>Request an access token using the configured client connection.</li><li>Inject the resulting bearer token into the HTTP request&#39;s <code>Authorization</code> header.</li></ul><p>This makes it easy to securely call external APIs that require OAuth2 or OpenID Connect authentication, without manually handling tokens in your workflow.</p><p><img src="'+a+'" alt="Use Client Connection in HTTP Request Task"></p>',15),c=[r];function l(u,d,h,g,p,C){return t(),n("div",null,c)}const T=e(s,[["render",l]]);export{f as __pageData,T as default};
